// ─── PEI SUBMIT EMOTION EDGE FUNCTION ────────────────────────────────────────
// Handles anonymous emotion submissions with rate limiting
// Deployed as a Supabase Edge Function

import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

// ─── CONSTANTS ────────────────────────────────────────────────────────────────
const VALID_EMOTIONS = [
  "longing", "hope", "anger", "anxiety",
    "grief", "relief", "determination", "regret"
    ];
    const MAX_SUBMISSIONS_PER_DAY = 3;
    const MAX_TEXT_LENGTH = 150;
    const MIN_THRESHOLD = 50; // submissions needed before LGU appears on map

    // ─── CORS HEADERS ─────────────────────────────────────────────────────────────
    const corsHeaders = {
      "Access-Control-Allow-Origin": "*",
        "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
          "Access-Control-Allow-Methods": "POST, OPTIONS",
          };

          // ─── HELPERS ──────────────────────────────────────────────────────────────────

          // Get ISO week number
          function getWeekNumber(date: Date): number {
            const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
              const dayNum = d.getUTCDay() || 7;
                d.setUTCDate(d.getUTCDate() + 4 - dayNum);
                  const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
                    return Math.ceil((((d.getTime() - yearStart.getTime()) / 86400000) + 1) / 7);
                    }

                    // Hash a string using SHA-256 (with daily rotating salt for anonymity)
                    async function hashWithSalt(value: string, salt: string): Promise<string> {
                      const encoder = new TextEncoder();
                        const data = encoder.encode(value + salt);
                          const hashBuffer = await crypto.subtle.digest("SHA-256", data);
                            const hashArray = Array.from(new Uint8Array(hashBuffer));
                              return hashArray.map(b => b.toString(16).padStart(2, "0")).join("");
                              }

                              // Daily salt — changes every midnight UTC
                              // After midnight, yesterday's hashes are useless. Anonymity is structurally guaranteed.
                              function getDailySalt(): string {
                                const today = new Date().toISOString().split("T")[0]; // "2026-03-03"
                                  return `pei-salt-${today}`;
                                  }

                                  // ─── MAIN HANDLER ─────────────────────────────────────────────────────────────
                                  Deno.serve(async (req: Request) => {

                                    // Handle CORS preflight
                                      if (req.method === "OPTIONS") {
                                          return new Response("ok", { headers: corsHeaders });
                                            }

                                              // Only accept POST
                                                if (req.method !== "POST") {
                                                    return new Response(
                                                          JSON.stringify({ error: "Method not allowed" }),
                                                                { status: 405, headers: { ...corsHeaders, "Content-Type": "application/json" } }
                                                                    );
                                                                      }

                                                                        try {
                                                                            // ─── PARSE BODY ───────────────────────────────────────────────────────────
                                                                                let body: {
                                                                                      lgu_id: string;
                                                                                            emotion: string;
                                                                                                  intensity: number;
                                                                                                        text?: string;
                                                                                                            };

                                                                                                                try {
                                                                                                                      body = await req.json();
                                                                                                                          } catch {
                                                                                                                                return new Response(
                                                                                                                                        JSON.stringify({ error: "Invalid JSON body" }),
                                                                                                                                                { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
                                                                                                                                                      );
                                                                                                                                                          }

                                                                                                                                                              const { lgu_id, emotion, intensity, text } = body;

                                                                                                                                                                  // ─── INPUT VALIDATION ─────────────────────────────────────────────────────

                                                                                                                                                                      if (!lgu_id || typeof lgu_id !== "string") {
                                                                                                                                                                            return new Response(
                                                                                                                                                                                    JSON.stringify({ error: "lgu_id is required" }),
                                                                                                                                                                                            { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
                                                                                                                                                                                                  );
                                                                                                                                                                                                      }

                                                                                                                                                                                                          if (!emotion || !VALID_EMOTIONS.includes(emotion.toLowerCase())) {
                                                                                                                                                                                                                return new Response(
                                                                                                                                                                                                                        JSON.stringify({ error: `emotion must be one of: ${VALID_EMOTIONS.join(", ")}` }),
                                                                                                                                                                                                                                { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
                                                                                                                                                                                                                                      );
                                                                                                                                                                                                                                          }

                                                                                                                                                                                                                                              if (!intensity || intensity < 1 || intensity > 5 || !Number.isInteger(intensity)) {
                                                                                                                                                                                                                                                    return new Response(
                                                                                                                                                                                                                                                            JSON.stringify({ error: "intensity must be an integer between 1 and 5" }),
                                                                                                                                                                                                                                                                    { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
                                                                                                                                                                                                                                                                          );
                                                                                                                                                                                                                                                                              }

                                                                                                                                                                                                                                                                                  if (text && text.length > MAX_TEXT_LENGTH) {
                                                                                                                                                                                                                                                                                        return new Response(
                                                                                                                                                                                                                                                                                                JSON.stringify({ error: `text must be ${MAX_TEXT_LENGTH} characters or fewer` }),
                                                                                                                                                                                                                                                                                                        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
                                                                                                                                                                                                                                                                                                              );
                                                                                                                                                                                                                                                                                                                  }

                                                                                                                                                                                                                                                                                                                      // ─── RATE LIMITING ────────────────────────────────────────────────────────
                                                                                                                                                                                                                                                                                                                          // Hash IP + user-agent with daily rotating salt
                                                                                                                                                                                                                                                                                                                              // After midnight UTC, yesterday's hashes are mathematically unrecoverable

                                                                                                                                                                                                                                                                                                                                  const ip = req.headers.get("x-forwarded-for")?.split(",")[0]?.trim()
                                                                                                                                                                                                                                                                                                                                              || req.headers.get("x-real-ip")
                                                                                                                                                                                                                                                                                                                                                          || "unknown";
                                                                                                                                                                                                                                                                                                                                                              const userAgent = req.headers.get("user-agent") || "unknown";
                                                                                                                                                                                                                                                                                                                                                                  const salt = getDailySalt();

                                                                                                                                                                                                                                                                                                                                                                      const ipHash     = await hashWithSalt(ip, salt);
                                                                                                                                                                                                                                                                                                                                                                          const deviceHash = await hashWithSalt(userAgent, salt);
                                                                                                                                                                                                                                                                                                                                                                              const hashKey    = await hashWithSalt(ipHash + deviceHash, salt);

                                                                                                                                                                                                                                                                                                                                                                                  const today = new Date().toISOString().split("T")[0];

                                                                                                                                                                                                                                                                                                                                                                                      // Use service role client for rate limit checks (bypasses RLS)
                                                                                                                                                                                                                                                                                                                                                                                          const supabaseAdmin = createClient(
                                                                                                                                                                                                                                                                                                                                                                                                Deno.env.get("SUPABASE_URL")!,
                                                                                                                                                                                                                                                                                                                                                                                                      Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!
                                                                                                                                                                                                                                                                                                                                                                                                          );

                                                                                                                                                                                                                                                                                                                                                                                                              // Check current count for today
                                                                                                                                                                                                                                                                                                                                                                                                                  const { data: rateData, error: rateError } = await supabaseAdmin
                                                                                                                                                                                                                                                                                                                                                                                                                        .from("rate_limits")
                                                                                                                                                                                                                                                                                                                                                                                                                              .select("count")
                                                                                                                                                                                                                                                                                                                                                                                                                                    .eq("hash_key", hashKey)
                                                                                                                                                                                                                                                                                                                                                                                                                                          .eq("date_bucket", today)
                                                                                                                                                                                                                                                                                                                                                                                                                                                .single();

                                                                                                                                                                                                                                                                                                                                                                                                                                                    if (rateError && rateError.code !== "PGRST116") {
                                                                                                                                                                                                                                                                                                                                                                                                                                                          // PGRST116 = no rows found, which is fine (first submission today)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                console.error("Rate limit check error:", rateError);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                      return new Response(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                              JSON.stringify({ error: "Service error. Please try again." }),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const currentCount = rateData?.count || 0;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (currentCount >= MAX_SUBMISSIONS_PER_DAY) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              return new Response(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      JSON.stringify({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                error: "You've already submitted 3 times today. Come back tomorrow.",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          code: "RATE_LIMITED"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          { status: 429, headers: { ...corsHeaders, "Content-Type": "application/json" } }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // ─── VERIFY LGU EXISTS ────────────────────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const { data: lguData, error: lguError } = await supabaseAdmin
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  .from("lgus")
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        .select("id, name, region_id")
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              .eq("id", lgu_id)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    .eq("active", true)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          .single();

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              if (lguError || !lguData) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return new Response(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            JSON.stringify({ error: "Invalid or inactive LGU" }),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  // ─── PROCESS TEXT (if provided) ───────────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      // Raw text is NEVER stored. Only AI-extracted signal metadata is kept.
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          let text_signal = null;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              if (text && text.trim().length > 0) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    // Basic sentiment signal without external API call for prototype
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          // In production: call Claude API here for proper emotion classification
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const lowerText = text.toLowerCase();

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      // Simple keyword-based signal extraction for prototype
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const positiveWords = ["hope", "happy", "grateful", "love", "excited", "proud", "blessed", "joy", "relief", "peace"];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const negativeWords = ["sad", "angry", "tired", "lost", "scared", "afraid", "alone", "hurt", "pain", "worried", "anxious"];

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const posCount = positiveWords.filter(w => lowerText.includes(w)).length;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const negCount = negativeWords.filter(w => lowerText.includes(w)).length;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    text_signal = {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            sentiment: posCount > negCount ? "positive" : negCount > posCount ? "negative" : "neutral",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    char_count: text.length,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            // Raw text is intentionally not stored here
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    processed_at: new Date().toISOString()
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                // text variable is discarded after this block — never inserted into DB
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // ─── WRITE SUBMISSION ─────────────────────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const now = new Date();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const weekNumber = getWeekNumber(now);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const year = now.getFullYear();

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const { error: insertError } = await supabaseAdmin
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              .from("submissions")
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    .insert({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            lgu_id,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    emotion: emotion.toLowerCase(),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            intensity,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    text_signal,           // AI signal only, never raw text
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            ip_hash:     ipHash,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    device_hash: deviceHash,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            week_number: weekNumber,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    year,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            submitted_at: now.toISOString()
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      if (insertError) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            console.error("Submission insert error:", insertError);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  return new Response(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          JSON.stringify({ error: "Failed to record submission. Please try again." }),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                // ─── UPDATE RATE LIMIT ────────────────────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const { error: upsertError } = await supabaseAdmin
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          .from("rate_limits")
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                .upsert({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        hash_key:    hashKey,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                date_bucket: today,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        count:       currentCount + 1
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }, { onConflict: "hash_key,date_bucket" });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  if (upsertError) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // Non-fatal — submission already recorded, rate limit just didn't update
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              console.warn("Rate limit upsert warning:", upsertError);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      // ─── TRIGGER AGGREGATION CHECK ────────────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          // Check if this LGU just crossed the threshold — if so, kick off aggregation
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              // For prototype: we'll run aggregation on a schedule, not per-submission
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  // This is just a count check to include in the response
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const { count: submissionCount } = await supabaseAdmin
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            .from("submissions")
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  .select("*", { count: "exact", head: true })
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        .eq("lgu_id", lgu_id);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const justCrossedThreshold = submissionCount === MIN_THRESHOLD;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                // ─── SUCCESS RESPONSE ─────────────────────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return new Response(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          JSON.stringify({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  acknowledged: true,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          lgu:          lguData.name,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  week:         weekNumber,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          year,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  submissions_remaining: MAX_SUBMISSIONS_PER_DAY - (currentCount + 1),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          ...(justCrossedThreshold && {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    milestone: `${lguData.name} just crossed the visibility threshold!`
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            })
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                status: 201,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        headers: { ...corsHeaders, "Content-Type": "application/json" }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  );

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    } catch (err) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        console.error("Unexpected error:", err);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            return new Response(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  JSON.stringify({ error: "An unexpected error occurred." }),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              